# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from flask import Flask, request, jsonify
import joblib

app = Flask(__name__)
vectorizer = None
model = None

@app.route('/train', methods=['POST'])
def train():
    global vectorizer, model
    data = request.get_json()
    emails = [email['text'] for email in data['emails']]
    labels = [email['spam'] for email in data['emails']]
    
    vectorizer = CountVectorizer(stop_words='english')
    features = vectorizer.fit_transform(emails)
    
    model = LogisticRegression()
    model.fit(features, labels)
    
    joblib.dump(vectorizer, 'vectorizer.joblib')
    joblib.dump(model, 'model.joblib')

    return jsonify({'status': 'Model trained successfully'}), 201

@app.route('/predict', methods=['POST'])
def predict():
    if not vectorizer or not model:
        return jsonify({'error': 'No trained model found, please train the model first.'}), 404
    
    data = request.get_json()
    email_text = [data['email']]
    
    features = vectorizer.transform(email_text)
    spam_probability = model.predict_proba(features)[0][1]
    
    return jsonify({'spam_probability': float(f"{spam_probability:.4f)}")})

if __name__ == '__main__':
    app.run()